#!/usr/bin/env python3
"""check-version-drift (R12.AC6): make a CLI change tool-prompted instead of memory-dependent.

Compares the installed `claude --version` to the recorded verified version
(meta/version-data.yaml `_verified_version`, mirrored in meta/version-record.md), and — where
feasible — diffs the installed `claude --help` command list against meta/cli-commands.snapshot to
surface new / removed / renamed commands that may need coverage.

Drift is informational by default (exit 0) so it never blocks day-to-day work; pass `--strict`
(used by the scheduled refresh trigger) to exit non-zero when drift is detected. This check is
itself the worked example U16 references for "Claude in CI / on a schedule" (R14.AC2).
"""
import os
import re
import subprocess
import sys

sys.path.insert(0, os.path.dirname(os.path.abspath(__file__)))
from _common import META, Reporter, load_version_data  # noqa: E402

SNAPSHOT = META / "cli-commands.snapshot"


def installed_version():
    out = subprocess.run(["claude", "--version"], capture_output=True, text=True, timeout=30)
    m = re.search(r"\d+\.\d+\.\d+", out.stdout)
    return m.group(0) if m else None


def installed_commands():
    out = subprocess.run(["claude", "--help"], capture_output=True, text=True, timeout=30)
    cmds = set()
    in_commands = False
    for line in out.stdout.splitlines():
        if line.rstrip() == "Commands:":
            in_commands = True
            continue
        if in_commands:
            # Command rows are indented exactly two spaces; wrapped description lines are
            # indented far more, so an exact two-space anchor excludes them.
            m = re.match(r" {2}([a-z][\w|-]*)", line)
            if m:
                cmds.add(m.group(1).split("|")[0])  # "plugin|plugins" -> "plugin"
    return cmds


def main(argv):
    strict = "--strict" in argv
    rep = Reporter("check-version-drift")
    recorded = load_version_data().get("_verified_version")

    try:
        installed = installed_version()
    except (FileNotFoundError, subprocess.SubprocessError) as exc:
        rep.pending(f"could not run `claude --version` ({exc}); skipping drift check")
        return rep.done(strict=False)

    if installed is None:
        rep.pending("could not parse installed CLI version; skipping")
        return rep.done(strict=False)

    if installed == recorded:
        rep.ok(f"installed CLI {installed} matches recorded verified version")
    else:
        rep.pending(f"DRIFT: installed {installed} != recorded {recorded} — re-verify "
                    f"version-specific facts and bump meta/version-record.md (R12.AC7)")

    # command-list diff (best effort)
    if SNAPSHOT.exists():
        recorded_cmds = {c.strip() for c in SNAPSHOT.read_text().split() if c.strip()}
        try:
            now = installed_commands()
            added, removed = sorted(now - recorded_cmds), sorted(recorded_cmds - now)
            if added:
                rep.pending(f"new CLI command(s) since snapshot: {added}")
            if removed:
                rep.pending(f"CLI command(s) removed since snapshot: {removed}")
            if not added and not removed:
                rep.ok(f"command list unchanged vs snapshot ({len(now)} commands)")
        except (FileNotFoundError, subprocess.SubprocessError) as exc:
            rep.pending(f"could not diff command list ({exc})")
    else:
        rep.pending(f"no command snapshot at {SNAPSHOT.name}; run `make snapshot` to create one")

    return rep.done(strict=strict)


if __name__ == "__main__":
    raise SystemExit(main(sys.argv[1:]))

#!/usr/bin/env python3
"""check-traceability (R13.AC5): the two-way traceability the spec promises.

  A. Every requirement R1–R15 is referenced by >= 1 course artifact (meta/, course/, tools/,
     .claude/, .github/ — i.e. the built course, not the spec that defines the requirements).
  B. Every can-do (C1–C17 + CV) traces to >= 1 LAB and >= 1 capstone-rubric dimension.

Parts B (and any not-yet-referenced requirement) depend on content authored in P5/P6. This check
is built before that content (so it guards as soon as content lands), therefore:
  - default mode: unmet items are reported as PENDING and do NOT fail the build;
  - `--strict` (the release / final Definition-of-Done gate): PENDING becomes FAIL.

A lab is detected as a `## Lab` heading in a unit; the can-dos it exercises are the unit's
front-matter `can_do`. Rubric dimensions are lines in course/capstone/rubric.md tagged with the
can-do id they assess, e.g. `- [C6] ...` (convention consumed here; authored in P6).
"""
import os
import re
import sys

sys.path.insert(0, os.path.dirname(os.path.abspath(__file__)))
from _common import (  # noqa: E402
    COURSE, META, ROOT, Reporter, iter_text_files, load_yaml, parse_frontmatter, unit_files,
)

REQ_RE = re.compile(r"\bR(?:1[0-5]|[1-9])\b")
CANDO_TAG_RE = re.compile(r"\b(C(?:1[0-7]|[1-9])|CV)\b")


def main(argv):
    strict = "--strict" in argv
    rep = Reporter("check-traceability")
    cap = load_yaml(META / "capability-map.yaml")
    cids = {c["id"] for c in cap["capabilities"]}

    # A. requirement references across the built course
    scan_roots = [META, COURSE, ROOT / "tools", ROOT / ".claude", ROOT / ".github",
                  ROOT / "README.md", ROOT / "CLAUDE.md"]
    referenced = set()
    for root in scan_roots:
        files = [root] if root.is_file() else list(iter_text_files(root))
        for path in files:
            try:
                referenced |= set(REQ_RE.findall(path.read_text(encoding="utf-8")))
            except (UnicodeDecodeError, IsADirectoryError):
                continue
    all_reqs = {f"R{i}" for i in range(1, 16)}
    missing_reqs = sorted(all_reqs - referenced, key=lambda r: int(r[1:]))
    if missing_reqs:
        rep.pending(f"requirements not yet referenced by a course artifact: {missing_reqs}")
    else:
        rep.ok("every requirement R1–R15 is referenced by a course artifact")

    # B. can-do -> lab and can-do -> rubric dimension
    lab_cands = set()
    for path in unit_files():
        fm = parse_frontmatter(path)
        if fm and "## Lab" in path.read_text(encoding="utf-8"):
            lab_cands |= set(fm.get("can_do", []))
    rubric = COURSE / "capstone" / "rubric.md"
    rubric_cands = set()
    if rubric.exists():
        rubric_cands = set(CANDO_TAG_RE.findall(rubric.read_text(encoding="utf-8")))

    no_lab = sorted(cids - lab_cands)
    no_rubric = sorted(cids - rubric_cands)
    if no_lab:
        rep.pending(f"can-do(s) not yet practiced by a lab: {no_lab}")
    else:
        rep.ok("every can-do is practiced by >=1 lab")
    if no_rubric:
        rep.pending(f"can-do(s) not yet assessed by a rubric dimension: {no_rubric}")
    else:
        rep.ok("every can-do is assessed by >=1 capstone-rubric dimension")

    return rep.done(strict=strict)


if __name__ == "__main__":
    raise SystemExit(main(sys.argv[1:]))
